import{_ as e,o as i,c as t,ae as s}from"./chunks/framework.EHGTsUvI.js";const o="/assets/https.DNUqWTlP.jpeg",g=JSON.parse('{"title":"网络","description":"","frontmatter":{},"headers":[],"relativePath":"frontend/network.md","filePath":"frontend/network.md","lastUpdated":1773300316000}'),l={name:"frontend/network.md"};function d(n,a,r,h,p,c){return i(),t("div",null,[...a[0]||(a[0]=[s('<h1 id="网络" tabindex="-1">网络 <a class="header-anchor" href="#网络" aria-label="Permalink to &quot;网络&quot;">​</a></h1><h2 id="http" tabindex="-1">HTTP <a class="header-anchor" href="#http" aria-label="Permalink to &quot;HTTP&quot;">​</a></h2><blockquote><p><a href="https://juejin.im/post/5d032b77e51d45777a126183" target="_blank" rel="noreferrer">面试官（9）：可能是全网最全的 http 面试答案</a></p></blockquote><h3 id="状态码" tabindex="-1">状态码 <a class="header-anchor" href="#状态码" aria-label="Permalink to &quot;状态码&quot;">​</a></h3><p><strong>1xx 表示客户端应该继续发送请求</strong></p><p><strong>2xx 表示成功的请求</strong></p><ul><li>200 OK 表示 OK，正常返回信息</li><li>201 Created 表示请求成功且服务器创建了新的资源</li><li>202 Accepted 表示服务器已经接受了请求，但还未处理</li><li>206 Partial Content 表示服务器已经处理了部分 GET 请求</li></ul><p><strong>3xx 表示重定向</strong></p><ul><li>301 Moved Permanently 表示永久重定向，请求的网页已经永久移动到新位置</li><li>302 Found 表示临时重定向</li><li>304 Not Modified 表示自从上一次请求以来，页面的内容没有改变过，常见协商缓存</li></ul><p><strong>4xx 表示客户端错误</strong></p><ul><li>400 Bad Request 表示服务器无法理解请求的格式，语义或请求参数有误</li><li>401 Unauthorized 表示当前请求需要用户验证</li><li>403 Fobidden 表示禁止访问</li><li>404 Not Found 表示请求的资源不存在，一般是路径写错了</li></ul><p><strong>5xx 表示服务器错误</strong></p><ul><li>500 Internal Server Error 表示最常见的服务器错误</li><li>502 Bad Gateway 表示网关错误</li><li>503 Service Unavailable 表示服务器暂时无法处理请求</li></ul><h2 id="https" tabindex="-1">HTTPS <a class="header-anchor" href="#https" aria-label="Permalink to &quot;HTTPS&quot;">​</a></h2><p>对称加密算法：加密和解密算法是公开的，密钥是保密的，加密和解密使用同一个密钥。</p><p>非对称加密 RSA 算法：一对儿钥匙，一个是保密的，称为私钥，另一个是公开的，称为公钥。用私钥加密的数据，只有对应的公钥才能解密，用公钥加密的数据， 只有对应的私钥才能解密。</p><p>非对称加密+对称加密：由于 RSA 算法加解密较慢，可以使用非对称加密传输对称加密密钥，再使用对称加密通信。</p><p>中间人攻击：劫取并伪装 RSA 公钥，导致用户使用了中间人的公钥加密。问题出现在公钥的分发。</p><p>数字签名和数字证书：有公信力的认证中心（CA）使用 Hash 算法对消息处理生成消息摘要，再用它的私钥对消息摘要加密，形成签名。消息+数字签名=数字证书。用户拿到证书后，使用相同的 Hash 算法生成消息摘要，再用 CA 的公钥解密数字签名，两份消息摘要进行对比，就知道有没有被篡改了。如果没有篡改，即得到服务器公钥。</p><p>HTTPS 流程：接上，拿到服务器公钥后，浏览器生成随机的对称密钥，使用服务器公钥加密，服务器用自己的私钥解密，得到对称密钥，双方都知道了安全的对称密钥，可以用来加密通信了。</p><p><img src="'+o+'" alt="https"></p><h2 id="xss-和-csrf-区别" tabindex="-1">XSS 和 CSRF 区别 <a class="header-anchor" href="#xss-和-csrf-区别" aria-label="Permalink to &quot;XSS 和 CSRF 区别&quot;">​</a></h2><ol><li>跨站脚本攻击（Cross Site Scripting)，为了不和层叠样式表 CSS 混淆，故将跨站脚本攻击缩写为 XSS。恶意攻击者往 Web 页面里插入恶意 Script 代码，当用户浏览该页之时，嵌入其中 Web 里面的 Script 代码会被执行，从而达到恶意攻击用户的目的。</li><li>跨站请求伪造（Cross-site request forgery），是伪造请求，冒充用户在站内的正常操作。我们知道，绝大多数网站是通过 cookie 等方式辨识用户身份，再予以授权的。所以要伪造用户的正常操作，最好的方法是通过 XSS 或链接欺骗等途径，让用户在本机（即拥有身份 cookie 的浏览器端）发起用户所不知道的请求。</li></ol><p>区别：</p><ul><li>原理不同，CSRF 是利用网站 A 本身的漏洞，去请求网站 A 的 api；XSS 是向目标网站注入 JS 代码，然后执行 JS 里的代码。</li><li>CSRF 需要用户先登录目标网站获取 cookie，而 XSS 不需要登录</li><li>CSRF 的目标是用户，XSS 的目标是服务器</li><li>XSS 是利用合法用户获取其信息，而 CSRF 是伪造成合法用户发起请求</li></ul><h2 id="缓存" tabindex="-1">缓存 <a class="header-anchor" href="#缓存" aria-label="Permalink to &quot;缓存&quot;">​</a></h2><p>缓存对于前端性能优化来说是个很重要的点，良好的缓存策略可以降低资源的重复加载提高网页的整体加载速度。</p><p>通常浏览器缓存策略分为两种：强缓存和协商缓存。</p><h3 id="强缓存" tabindex="-1">强缓存 <a class="header-anchor" href="#强缓存" aria-label="Permalink to &quot;强缓存&quot;">​</a></h3><p>实现强缓存可以通过两种响应头实现：<code>Expires</code> 和 <code>Cache-Control</code> 。强缓存表示在缓存期间不需要请求，<code>state code</code> 为 200</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Expires</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: Wed, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">22</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Oct </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2018</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 08</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">41</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">00</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> GMT</span></span></code></pre></div><p><code>Expires</code> 是 HTTP / 1.0 的产物，表示资源会在 <code>Wed, 22 Oct 2018 08:41:00 GMT</code> 后过期，需要再次请求。并且 <code>Expires</code> 受限于本地时间，如果修改了本地时间，可能会造成缓存失效。</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Cache</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">control</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: max</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">age</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">30</span></span></code></pre></div><p><code>Cache-Control</code> 出现于 HTTP / 1.1，优先级高于 <code>Expires</code> 。该属性表示资源会在 30 秒后过期，需要再次请求。</p><h3 id="协商缓存" tabindex="-1">协商缓存 <a class="header-anchor" href="#协商缓存" aria-label="Permalink to &quot;协商缓存&quot;">​</a></h3><p>如果缓存过期了，我们就可以使用协商缓存来解决问题。协商缓存需要请求，如果缓存有效会返回 304。</p><p>协商缓存需要客户端和服务端共同实现，和强缓存一样，也有两种实现方式。</p><h5 id="last-modified-和-if-modified-since" tabindex="-1">Last-Modified 和 If-Modified-Since <a class="header-anchor" href="#last-modified-和-if-modified-since" aria-label="Permalink to &quot;Last-Modified 和 If-Modified-Since&quot;">​</a></h5><p><code>Last-Modified</code> 表示本地文件最后修改日期，<code>If-Modified-Since</code> 会将 <code>Last-Modified</code> 的值发送给服务器，询问服务器在该日期后资源是否有更新，有更新的话就会将新的资源发送回来。</p><p>但是如果在本地打开缓存文件，就会造成 <code>Last-Modified</code> 被修改，所以在 HTTP / 1.1 出现了 <code>ETag</code>。</p><h5 id="etag-和-if-none-match" tabindex="-1">ETag 和 If-None-Match <a class="header-anchor" href="#etag-和-if-none-match" aria-label="Permalink to &quot;ETag 和 If-None-Match&quot;">​</a></h5><p><code>ETag</code> 类似于文件指纹，<code>If-None-Match</code> 会将当前 <code>ETag</code> 发送给服务器，询问该资源 <code>ETag</code> 是否变动，有变动的话就将新的资源发送回来。并且 <code>ETag</code> 优先级比 <code>Last-Modified</code> 高。</p><h3 id="选择合适的缓存策略" tabindex="-1">选择合适的缓存策略 <a class="header-anchor" href="#选择合适的缓存策略" aria-label="Permalink to &quot;选择合适的缓存策略&quot;">​</a></h3><p>对于大部分的场景都可以使用强缓存配合协商缓存解决，但是在一些特殊的地方可能需要选择特殊的缓存策略</p><ul><li>对于某些不需要缓存的资源，可以使用 <code>Cache-control: no-store</code> ，表示该资源不需要缓存</li><li>对于频繁变动的资源，可以使用 <code>Cache-Control: no-cache</code> 并配合 <code>ETag</code> 使用，表示该资源已被缓存，但是每次都会发送请求询问资源是否更新。</li><li>对于代码文件来说，通常使用 <code>Cache-Control: max-age=31536000</code> 并配合策略缓存使用，然后对文件进行指纹处理，一旦文件名变动就会立刻下载新的文件。</li></ul><h3 id="使用-http-2-0" tabindex="-1">使用 HTTP / 2.0 <a class="header-anchor" href="#使用-http-2-0" aria-label="Permalink to &quot;使用 HTTP / 2.0&quot;">​</a></h3><p>因为浏览器会有并发请求限制，在 HTTP / 1.1 时代，每个请求都需要建立和断开，消耗了好几个 RTT 时间，并且由于 TCP 慢启动的原因，加载体积大的文件会需要更多的时间。</p><p>在 HTTP / 2.0 中引入了多路复用，能够让多个请求使用同一个 TCP 链接，极大的加快了网页的加载速度。并且还支持 Header 压缩，进一步的减少了请求的数据大小。</p>',48)])])}const u=e(l,[["render",d]]);export{g as __pageData,u as default};
